mapper.select:
SELECT * FROM ( SELECT ROWNUM AS RNUM, A.* FROM ( SELECT C.COMPANY_NUMBER, C.COMPANY_NAME, C.COMPANY_ADDRESS, C.COMPANY_STATE, CI.COMP_SUMMARY, F.FILE_PATH, TO_CHAR(CI.COMP_PAGE_DATE, 'YYYY.MM.DD') AS COMP_PAGE_DATE, NVL(JP.CAT1_IS_HIRING, 0) AS CAT1_IS_HIRING, NVL(JP.CAT2_IS_HIRING, 0) AS CAT2_IS_HIRING, NVL(JP.CAT3_IS_HIRING, 0) AS CAT3_IS_HIRING, NVL(JP.CAT4_IS_HIRING, 0) AS CAT4_IS_HIRING FROM TBL_COMPANY C JOIN TBL_COMP_INFO CI ON C.COMPANY_NUMBER = CI.COMPANY_NUMBER LEFT JOIN TBL_FILE F ON C.COMPANY_NUMBER = F.COMPANY_NUMBER LEFT JOIN TBL_JOB_POST JP ON C.COMPANY_NUMBER = JP.COMPANY_NUMBER
WHERE C.COMPANY_NAME LIKE '%' || #{keyword} || '%'
ORDER BY C.COMPANY_NUMBER DESC ) A ) WHERE RNUM BETWEEN #{startRow} AND #{endRow}
